const checkpoints = [];

const products = JSON.parse(localStorage.getItem('products') || '[]');
const quoteListId = localStorage.getItem('current_quote_list_id');
const allQuoteItems = JSON.parse(localStorage.getItem('quote_list_items') || '[]');
const quoteItems = quoteListId ? allQuoteItems.filter(i => i.quote_list_id === quoteListId) : [];

// All catalog DAF products that meet task criteria
const qualifyingDafs = products.filter(p =>
  p && p.category_id === 'daf' && p.product_type === 'daf_unit' &&
  p.status === 'active' && p.currency === 'usd' &&
  typeof p.flow_capacity_min_m3h === 'number' && p.flow_capacity_min_m3h >= 50 &&
  typeof p.price === 'number' && p.price <= 80000
);
qualifyingDafs.sort((a, b) => (a.price || 0) - (b.price || 0));
const cheapestQualifying = qualifyingDafs[0] || null;

// Quote list items that are qualifying DAFs
const qualifyingInQuote = quoteItems.filter(item => {
  const product = products.find(p => p.id === item.product_id);
  return product &&
    product.category_id === 'daf' &&
    product.product_type === 'daf_unit' &&
    product.status === 'active' && product.currency === 'usd' &&
    typeof product.flow_capacity_min_m3h === 'number' && product.flow_capacity_min_m3h >= 50 &&
    typeof product.price === 'number' && product.price <= 80000;
});

// CP1 (0.4): User added at least one DAF that meets all flow and price criteria
checkpoints.push({
  passed: qualifyingInQuote.length > 0,
  weight: 0.4
});

// CP2 (0.6): User added the cheapest qualifying DAF from the catalog to the quote list
let hasCheapest = false;
if (cheapestQualifying) {
  hasCheapest = quoteItems.some(i => i.product_id === cheapestQualifying.id);
}
checkpoints.push({
  passed: !!cheapestQualifying && hasCheapest,
  weight: 0.6
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const products = JSON.parse(localStorage.getItem('products') || '[]');
const quoteListId = localStorage.getItem('current_quote_list_id');
const allQuoteItems = JSON.parse(localStorage.getItem('quote_list_items') || '[]');
const quoteItems = quoteListId ? allQuoteItems.filter(i => i.quote_list_id === quoteListId) : [];

const designFlow = 30;
const maxBudget = 150000;

// Helper to pick cheapest suitable product arrays
const screeningCandidates = products.filter(p =>
  p && p.category_id === 'screening' && p.product_type === 'screening_unit' &&
  p.status === 'active' &&
  typeof p.flow_capacity_min_m3h === 'number' && typeof p.flow_capacity_max_m3h === 'number' &&
  p.flow_capacity_min_m3h <= designFlow && p.flow_capacity_max_m3h >= designFlow &&
  typeof p.price === 'number'
);
screeningCandidates.sort((a, b) => (a.price || 0) - (b.price || 0));
const chosenScreen = screeningCandidates[0] || null;

const dosingCandidates = products.filter(p =>
  p && p.category_id === 'dosing_skids' && p.product_type === 'dosing_skid' &&
  p.status === 'active' &&
  typeof p.flow_capacity_min_m3h === 'number' && typeof p.flow_capacity_max_m3h === 'number' &&
  p.flow_capacity_min_m3h <= designFlow && p.flow_capacity_max_m3h >= designFlow &&
  typeof p.price === 'number'
);
dosingCandidates.sort((a, b) => (a.price || 0) - (b.price || 0));
const chosenDose = dosingCandidates[0] || null;

const dewateringCandidates = products.filter(p =>
  p && p.category_id === 'dewatering' && p.product_type === 'sludge_dewatering_unit' &&
  p.status === 'active' &&
  typeof p.plant_flow_capacity_m3h === 'number' && p.plant_flow_capacity_m3h >= designFlow &&
  typeof p.price === 'number'
);
dewateringCandidates.sort((a, b) => (a.price || 0) - (b.price || 0));
const chosenDewater = dewateringCandidates[0] || null;

const chosenProducts = [chosenScreen, chosenDose, chosenDewater].filter(Boolean);
const chosenIds = chosenProducts.map(p => p.id);
const chosenTotalPrice = chosenProducts.reduce((sum, p) => sum + (p.price || 0), 0);

let mostExpensive = null;
if (chosenProducts.length > 0) {
  mostExpensive = chosenProducts.slice().sort((a, b) => (b.price || 0) - (a.price || 0))[0];
}

let expectedFinalIds = chosenIds.slice();
if (chosenTotalPrice > maxBudget && mostExpensive) {
  expectedFinalIds = chosenIds.filter(id => id !== mostExpensive.id);
}

const quoteProductIds = quoteItems.map(i => i.product_id);
const hasAllExpected = expectedFinalIds.length > 0 && expectedFinalIds.every(id => quoteProductIds.includes(id));

// CP1 (0.5): User's quote list contains the cheapest suitable item for each category, adjusted for the budget rule (expected final set)
checkpoints.push({
  passed: hasAllExpected,
  weight: 0.5
});

// CP2 (0.5): Budget adjustment rule applied correctly:
// - If total <= budget: all three cheapest suitable items are present
// - If total > budget: the single most expensive of the three is NOT present, but the cheaper ones are
let budgetRuleOk = false;
if (chosenProducts.length === 0) {
  budgetRuleOk = false;
} else if (chosenTotalPrice <= maxBudget) {
  // Should keep all chosen products
  budgetRuleOk = chosenIds.length > 0 && chosenIds.every(id => quoteProductIds.includes(id));
} else if (mostExpensive) {
  const cheaperIds = chosenIds.filter(id => id !== mostExpensive.id);
  const hasCheaper = cheaperIds.length > 0 && cheaperIds.every(id => quoteProductIds.includes(id));
  const removedExpensive = !quoteProductIds.includes(mostExpensive.id);
  budgetRuleOk = hasCheaper && removedExpensive;
}

checkpoints.push({
  passed: budgetRuleOk,
  weight: 0.5
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const plans = JSON.parse(localStorage.getItem('maintenance_plans') || '[]');
const inquiryId = localStorage.getItem('current_service_inquiry_id');
const allItems = JSON.parse(localStorage.getItem('service_inquiry_items') || '[]');
const inquiryItems = inquiryId ? allItems.filter(i => i.service_inquiry_id === inquiryId) : [];

// Qualifying maintenance plans per task criteria
const qualifyingPlans = plans.filter(p =>
  p && p.service_type === 'maintenance_plans' &&
  p.country === 'germany' &&
  p.equipment_type === 'membrane_bioreactor_systems' &&
  p.status === 'active' && p.currency === 'eur' &&
  typeof p.response_time_hours === 'number' && p.response_time_hours <= 24 &&
  typeof p.annual_cost === 'number' && p.annual_cost <= 6000
);
qualifyingPlans.sort((a, b) => (a.annual_cost || 0) - (b.annual_cost || 0));
const cheapestPlan = qualifyingPlans[0] || null;

// Service inquiry items that correspond to qualifying plans
const qualifyingInInquiry = inquiryItems.filter(item => {
  const plan = plans.find(p => p.id === item.maintenance_plan_id);
  return plan &&
    plan.service_type === 'maintenance_plans' &&
    plan.country === 'germany' &&
    plan.equipment_type === 'membrane_bioreactor_systems' &&
    plan.status === 'active' && plan.currency === 'eur' &&
    typeof plan.response_time_hours === 'number' && plan.response_time_hours <= 24 &&
    typeof plan.annual_cost === 'number' && plan.annual_cost <= 6000;
});

// CP1 (0.4): User added at least one maintenance plan meeting all criteria to the service inquiry
checkpoints.push({
  passed: qualifyingInInquiry.length > 0,
  weight: 0.4
});

// CP2 (0.6): User added the cheapest qualifying plan from the catalog to the service inquiry
let hasCheapest = false;
if (cheapestPlan) {
  hasCheapest = inquiryItems.some(i => i.maintenance_plan_id === cheapestPlan.id);
}
checkpoints.push({
  passed: !!cheapestPlan && hasCheapest,
  weight: 0.6
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const resources = JSON.parse(localStorage.getItem('resource_items') || '[]');
const readingListId = localStorage.getItem('current_reading_list_id');
const allRlItems = JSON.parse(localStorage.getItem('reading_list_items') || '[]');
const rlItems = readingListId ? allRlItems.filter(i => i.reading_list_id === readingListId) : [];

// Qualifying 2023 F&B case studies with capacity ≥100 m3/day
const qualifyingCases = resources.filter(r => {
  if (!r || r.resource_type !== 'case_studies' || r.industry !== 'food_beverage') return false;
  const year = typeof r.publication_year === 'number'
    ? r.publication_year
    : (r.publication_date ? new Date(r.publication_date).getFullYear() : null);
  if (year !== 2023) return false;
  return typeof r.plant_capacity_m3_per_day === 'number' && r.plant_capacity_m3_per_day >= 100;
});
qualifyingCases.sort((a, b) => (b.publication_date || '').localeCompare(a.publication_date || ''));
const mostRecent = qualifyingCases[0] || null;

// Reading list items that correspond to qualifying case studies
const savedQualifying = rlItems.filter(item => qualifyingCases.some(r => r.id === item.resource_id));

// CP1 (0.4): User saved at least one case study meeting all industry, year, and capacity criteria
checkpoints.push({
  passed: savedQualifying.length > 0,
  weight: 0.4
});

// CP2 (0.6): User saved the most recently published qualifying case study
let hasMostRecent = false;
if (mostRecent) {
  hasMostRecent = rlItems.some(i => i.resource_id === mostRecent.id);
}
checkpoints.push({
  passed: !!mostRecent && hasMostRecent,
  weight: 0.6
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const calcs = JSON.parse(localStorage.getItem('equalization_tank_calculations') || '[]');
const products = JSON.parse(localStorage.getItem('products') || '[]');
const quoteListId = localStorage.getItem('current_quote_list_id');
const allQuoteItems = JSON.parse(localStorage.getItem('quote_list_items') || '[]');
const quoteItems = quoteListId ? allQuoteItems.filter(i => i.quote_list_id === quoteListId) : [];

// Find a calculation run with the specified inputs
const correctCalc = calcs.find(c =>
  c && c.flow_rate_value === 75 && c.flow_rate_unit === 'm3_per_h' &&
  c.peak_factor === 2.5 && c.buffer_time_hours === 4
) || null;

// CP1 (0.4): User ran the equalization tank calculator with the exact required inputs
checkpoints.push({
  passed: !!correctCalc,
  weight: 0.4
});

// CP2 (0.6): From that calculation, user added the correct equalization tank (closest volume ≥750 m3 in the recommended series, cheapest at that volume) to the quote list
let tankSelectionOk = false;
if (correctCalc) {
  const targetMinVolume = 750;
  const selectedSeriesId = correctCalc.selected_tank_series_id;
  if (selectedSeriesId) {
    const candidateTanks = products.filter(p =>
      p && p.product_type === 'equalization_tank' &&
      p.tank_series_id === selectedSeriesId &&
      typeof p.tank_volume_m3 === 'number' && p.tank_volume_m3 >= targetMinVolume &&
      typeof p.price === 'number' && p.status === 'active'
    );
    candidateTanks.sort((a, b) => {
      const va = a.tank_volume_m3 || 0;
      const vb = b.tank_volume_m3 || 0;
      if (va !== vb) return va - vb; // closest volume ≥ target first
      return (a.price || 0) - (b.price || 0); // then cheapest at that volume
    });
    const chosenTank = candidateTanks[0] || null;
    if (chosenTank) {
      tankSelectionOk = quoteItems.some(i => i.product_id === chosenTank.id);
    }
  }
}

checkpoints.push({
  passed: tankSelectionOk,
  weight: 0.6
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const products = JSON.parse(localStorage.getItem('products') || '[]');
const sessionId = localStorage.getItem('current_comparison_session_id');
const allCompItems = JSON.parse(localStorage.getItem('product_comparison_items') || '[]');
const compItems = sessionId ? allCompItems.filter(i => i.comparison_session_id === sessionId) : [];
const quoteRequests = JSON.parse(localStorage.getItem('quote_requests') || '[]');
const allQuoteItems = JSON.parse(localStorage.getItem('quote_list_items') || '[]');

// Qualifying pH systems
const qualifyingPhSystems = products.filter(p =>
  p && p.category_id === 'ph_neutralization_systems' &&
  p.product_type === 'ph_neutralization_system' &&
  p.status === 'active' && p.currency === 'usd' &&
  typeof p.price === 'number' && p.price <= 40000
);
qualifyingPhSystems.sort((a, b) => (a.price || 0) - (b.price || 0));
const cheapestTwo = qualifyingPhSystems.slice(0, 2);

// CP1 (0.4): Comparison session includes both of the two cheapest qualifying pH systems
let comparisonOk = false;
if (cheapestTwo.length === 2 && compItems.length > 0) {
  const compProductIds = compItems.map(i => i.product_id);
  comparisonOk = cheapestTwo.every(p => compProductIds.includes(p.id));
}
checkpoints.push({
  passed: comparisonOk,
  weight: 0.4
});

// CP2 (0.6): User submitted a quote request that includes the system with lower NaOH consumption among those two
let quoteOk = false;
let chosenLower = null;
if (cheapestTwo.length === 2) {
  const [p1, p2] = cheapestTwo;
  const c1 = (typeof p1.naoh_consumption_kg_per_h === 'number') ? p1.naoh_consumption_kg_per_h : Infinity;
  const c2 = (typeof p2.naoh_consumption_kg_per_h === 'number') ? p2.naoh_consumption_kg_per_h : Infinity;
  if (c1 === c2) {
    chosenLower = p1; // tie, any is acceptable
  } else {
    chosenLower = c1 < c2 ? p1 : p2;
  }
}

if (chosenLower && quoteRequests.length > 0) {
  for (const qr of quoteRequests) {
    if (qr.status !== 'submitted') continue;
    const itemsForList = allQuoteItems.filter(i => i.quote_list_id === qr.quote_list_id);
    if (itemsForList.some(i => i.product_id === chosenLower.id)) {
      quoteOk = true;
      break;
    }
  }
}

checkpoints.push({
  passed: !!chosenLower && quoteOk,
  weight: 0.6
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const searches = JSON.parse(localStorage.getItem('distributor_searches') || '[]');
const lastDetails = JSON.parse(localStorage.getItem('task7_lastDistributorDetails') || 'null');

// Find the most recent search matching the task criteria
const matchingSearches = searches.filter(s =>
  s && s.zip_postal_code === '75201' &&
  s.market_segment === 'industrial_wastewater_treatment' &&
  typeof s.radius_km === 'number' && s.radius_km <= 200
);
const lastSearch = matchingSearches.length > 0 ? matchingSearches[matchingSearches.length - 1] : null;

// CP1 (0.4): User performed a distributor search with ZIP 75201, market 'industrial_wastewater_treatment', and radius ≤200 km
checkpoints.push({
  passed: !!lastSearch,
  weight: 0.4
});

// CP2 (0.6): User viewed contact details for the closest distributor from that search
let viewedNearest = false;
if (lastSearch && Array.isArray(lastSearch.result_distributor_ids) && lastSearch.result_distributor_ids.length > 0 && lastDetails) {
  const nearestId = lastSearch.result_distributor_ids[0];
  viewedNearest = lastDetails.distributor_id === nearestId;
}

checkpoints.push({
  passed: viewedNearest,
  weight: 0.6
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const resources = JSON.parse(localStorage.getItem('resource_items') || '[]');
const registrations = JSON.parse(localStorage.getItem('webinar_registrations') || '[]');

// Determine qualifying PFAS webinars in June 2025 in 10:00–12:00 window
const qualifyingWebinars = resources.filter(r => {
  if (!r || r.resource_type !== 'webinars' || r.topic !== 'pfas_treatment' || !r.start_datetime) return false;
  const d = new Date(r.start_datetime);
  if (isNaN(d.getTime())) return false;
  const month = d.getMonth() + 1;
  const year = d.getFullYear();
  const hh = String(d.getHours()).padStart(2, '0');
  const mm = String(d.getMinutes()).padStart(2, '0');
  const timeStr = hh + ':' + mm;
  return year === 2025 && month === 6 && timeStr >= '10:00' && timeStr <= '12:00';
});
const targetWebinar = qualifyingWebinars[0] || null;

// Registrations for that webinar
const matchingRegs = targetWebinar
  ? registrations.filter(reg => reg && reg.webinar_id === targetWebinar.id)
  : [];

// CP1 (0.4): User registered for a webinar that meets topic, month/year, and time window criteria
checkpoints.push({
  passed: !!targetWebinar && matchingRegs.length > 0,
  weight: 0.4
});

// CP2 (0.6): Among those registrations, at least one uses the specified attendee details
let detailsOk = false;
if (targetWebinar && matchingRegs.length > 0) {
  detailsOk = matchingRegs.some(reg => {
    const nameOk = reg.full_name === 'Alex Rivera';
    const emailOk = reg.email === 'alex.rivera@example.com';
    const companyOk = reg.company === 'TexFab Coatings';
    const countryVal = (reg.country || '').toString().toLowerCase();
    const countryOk = countryVal === 'united_states' || countryVal === 'united states';
    const roleVal = (reg.role || '').toString().toLowerCase();
    const roleOk = roleVal === 'engineering_manager' || roleVal === 'engineering manager';
    return nameOk && emailOk && companyOk && countryOk && roleOk;
  });
}

checkpoints.push({
  passed: detailsOk,
  weight: 0.6
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
